import logo from './logo.svg';
import './App.css';
import UserModule from './userapp';
import Userlist from './userlist';
import 'bootstrap/dist/css/bootstrap.css';

function App() {
  let name = localStorage.getItem("fullname");
  if(name  == null)
   return (<UserModule/>)
  else{
    return (
      <HashRouter>            
        <Link to="/"> </Link>

        <Routes>
          <Route exact path="/edituser" element={<Userlist/>} />
        </Routes>
      </HashRouter>
    )
  }

}

export default App;
